import { configureStore } from "@reduxjs/toolkit";
import { authApi } from "@/business/api";
import sessionReducer from "./sessionSlice";
import {useDispatch, useSelector} from "react-redux";

export const store = configureStore({
  reducer: {
    session: sessionReducer,
    [authApi.reducerPath]: authApi.reducer,
  },
  middleware: (getDefaultMiddleware) =>
    getDefaultMiddleware().concat(authApi.middleware),
});

export type RootState = ReturnType<typeof store.getState>;
export type RootDispatch = typeof store.dispatch;
export const useAppSelector = useSelector.withTypes<RootState>();
export const useAppDispatch = useDispatch.withTypes<RootDispatch>();

import { configureStore } from "@reduxjs/toolkit";
import { authApi } from "@/business/api";
import { useDispatch, useSelector } from "react-redux";
import sessionReducer, { sessionSlice } from "./sessionSlice";

export const store = configureStore({
  reducer: {
    session: sessionReducer,
    [authApi.reducerPath]: authApi.reducer,
  },
  middleware: (getDefaultMiddleware) =>
    getDefaultMiddleware().concat(authApi.middleware),
});

export type RootState = ReturnType<typeof store.getState>;
export type RootDispatch = typeof store.dispatch;

export const useAppSelector = useSelector.withTypes<RootState>();
export const useAppDispatch = useDispatch.withTypes<RootDispatch>();

// Глобальные селекторы — принимают root state, не slice state.
// Экспортируются здесь, чтобы useSession не знал про "state.session".
export const { getToken, getUser } = sessionSlice.getSelectors<RootState>(
  (state) => state.session,
);

import { createSlice, type PayloadAction } from "@reduxjs/toolkit";
import type { User } from "@/business/types";

const TOKEN_KEY = "authToken";
const USER_KEY = "authUser";

export interface SessionState {
  token: string | null;
  user: User | null;
}

function getInitialState(): SessionState {
  if (typeof window === "undefined") {
    return { token: null, user: null };
  }
  const token = localStorage.getItem(TOKEN_KEY); //TODO: на куки
  let user: User | null = null;
  try {
    const raw = localStorage.getItem(USER_KEY);
    user = raw ? (JSON.parse(raw) as User) : null;
  } catch {
    user = null;
  }
  return { token, user };
}

const sessionSlice = createSlice({
  name: "session",
  initialState: getInitialState,
  selectors: {
    getToken: (state) => state.token,
    getUser: (state) => state.user,
  },
  reducers: {
    setCredentials: (
      state,
      action: PayloadAction<{ token: string; user: User | null }>,
    ) => {
      state.token = action.payload.token;
      state.user = action.payload.user;
      if (typeof window !== "undefined") {
        localStorage.setItem(TOKEN_KEY, action.payload.token);
        localStorage.setItem(USER_KEY, JSON.stringify(action.payload.user));
      }
    },
    logout: (state) => {
      state.token = null;
      state.user = null;
      if (typeof window !== "undefined") {
        localStorage.removeItem(TOKEN_KEY);
        localStorage.removeItem(USER_KEY);
      }
    },
  },
});

export const { setCredentials, logout } = sessionSlice.actions;
export default sessionSlice.reducer;

